UPDATE public.garden_import_queue SET
  payload = '{"species": "Tarragon", "species_slug": "tarragon", "varieties": [{"name": "Mexican Tarragon (Standard)", "slug": "mexican-tarragon-standard", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 0, "origin": "Mexico and Central America, traditional cultivation since Aztec times (pre-1500s)", "traits": "Bushy perennial herb, 60-90cm tall, 30-45cm wide. Bright green, narrow, oblong leaves (7.5cm long). Golden-yellow, five-petaled marigold-like flowers in clusters, blooming profusely late summer to autumn.", "flesh_fruit": "", "yield_notes": "High productivity. Continuous harvest spring through autumn. Can produce year-round in frost-free humid subtropical climates winters.", "growing_notes": "", "availability": "The Seed Collection (Australia-wide delivery including QLD), available as seeds. Quality Plants & Seedlings (express delivery to QLD). Plantmark Wholesale Nursery. Can be grown from seed sown after last frost or started indoors."}, {"name": "Mexican Mint Marigold", "slug": "mexican-mint-marigold", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 1, "origin": "Same as Mexican Tarragon (alternative common name)", "traits": "Identical to Mexican Tarragon. Upright growth habit, can reach up to 36 inches (90cm) in warm climates with woody stems.", "flesh_fruit": "", "yield_notes": "Excellent continuous production.", "growing_notes": "", "availability": "Same suppliers as Mexican Tarragon (same plant, different name)."}, {"name": "Texas Tarragon / Winter Tarragon", "slug": "texas-tarragon-winter-tarragon", "lineage_type": "open_pollinated", "climate_slug": "humid-subtropical", "sort_order": 2, "origin": "Southwestern United States and Mexico", "traits": "Regional name for Mexican Tarragon. Dark green, narrow leaves with slight shine. Grows 60-91cm tall.", "flesh_fruit": "", "yield_notes": "Very productive, year-round in mild winters.", "growing_notes": "", "availability": "Australian